function attachListeners() {
  document.addEventListener("mouseup", onMouseup, true);
  document.addEventListener("mousedown", onMousedown, true);
  document.addEventListener("keydown", onKeydown, true);
  window.addEventListener("blur", onBlur, true);
  document.addEventListener("visibilitychange", onVisibilityChange, true);
  window.addEventListener("scroll", onScrollOrResize, true);
  window.addEventListener("resize", onScrollOrResize, true);
  document.addEventListener("qute-translate-show", onTranslateShow, true);

  // Hover bubble listeners
  document.addEventListener("mouseover", onMouseover, true);
  document.addEventListener("mouseout", onMouseout, true);
  document.addEventListener("focusin", onFocusin, true);
  document.addEventListener("focusout", onFocusout, true);
  document.addEventListener("dragstart", onDragstart, true);
}

function onMouseover(e) {
  if (!CONFIG.hoverBubbleEnabled) {
    return;
  }

  const target = e.target;
  const link = findNearestLink(target);
  if (!link) {
    return;
  }

  const href = link.getAttribute("href");
  if (!isValidLinkUrl(href)) {
    return;
  }

  state.hoveredLink = link;
  state.hoveredUrl = href;
  showHoverBubble(href);
}

function onMouseout(e) {
  if (!CONFIG.hoverBubbleEnabled || !state.hoverBubbleActive) {
    return;
  }

  const target = e.target;
  const link = findNearestLink(target);
  if (!link || link !== state.hoveredLink) {
    return;
  }

  const related = e.relatedTarget;
  const relatedLink = related ? findNearestLink(related) : null;
  if (relatedLink && relatedLink === state.hoveredLink) {
    return;
  }

  hideHoverBubble("mouseout");
}

function onFocusin(e) {
  if (!CONFIG.hoverBubbleEnabled) {
    return;
  }

  const target = e.target;
  const link = findNearestLink(target);
  if (!link) {
    return;
  }

  const href = link.getAttribute("href");
  if (!isValidLinkUrl(href)) {
    return;
  }

  state.hoveredLink = link;
  state.hoveredUrl = href;
  showHoverBubble(href);
}

function onFocusout(e) {
  if (!CONFIG.hoverBubbleEnabled || !state.hoverBubbleActive) {
    return;
  }

  const target = e.target;
  const link = findNearestLink(target);
  if (!link || link !== state.hoveredLink) {
    return;
  }

  const related = e.relatedTarget;
  const relatedLink = related ? findNearestLink(related) : null;
  if (relatedLink && relatedLink === state.hoveredLink) {
    return;
  }

  hideHoverBubble("focusout");
}

function findNearestLink(node) {
  if (!node) {
    return null;
  }
  if (node.nodeType === 1 && node.nodeName === "A") {
    return node;
  }
  return node.closest("a");
}

function isValidLinkUrl(href) {
  if (typeof href !== "string" || !href) {
    return false;
  }
  const trimmed = href.trim();
  if (!trimmed) {
    return false;
  }
  if (trimmed === "#") {
    return false;
  }
  if (trimmed.startsWith("javascript:")) {
    return false;
  }
  if (!trimmed.startsWith("http://") && !trimmed.startsWith("https://")) {
    return false;
  }
  return true;
}

function showHoverBubble(url) {
  ensureUi();
  ensureHoverBubbleUi();

  ui.hoverBubbleContent.textContent = url;
  ui.hoverBubble.dataset.theme = resolveTooltipTheme(null);
  ui.hoverBubble.dataset.open = "1";

  state.hoverBubbleActive = true;
}

function hideHoverBubble(reason) {
  if (!ui || !ui.hoverBubble) {
    return;
  }

  ui.hoverBubble.dataset.open = "0";
  ui.hoverBubbleContent.textContent = "";

  state.hoverBubbleActive = false;
  state.hoveredLink = null;
  state.hoveredUrl = null;
}

function ensureHoverBubbleUi() {
  if (ui && ui.hoverBubble) {
    return;
  }

  const hoverBubble = document.createElement("div");
  hoverBubble.className = "HoverBubble";
  hoverBubble.setAttribute("role", "status");
  hoverBubble.dataset.open = "0";
  hoverBubble.dataset.theme = "light";

  const content = document.createElement("div");
  content.className = "HoverBubbleContent";
  content.textContent = "";

  hoverBubble.appendChild(content);
  ui.shadow.appendChild(hoverBubble);

  ui.hoverBubble = hoverBubble;
  ui.hoverBubbleContent = content;
}

if (!ui) {
  return;
}

const host = document.createElement("div");
host.setAttribute("data-qute-translate-selection-tooltip", "1");
host.style.position = "fixed";
host.style.left = "0";
host.style.top = "0";
host.style.width = "0";
host.style.height = "0";
host.style.zIndex = "2147483647";

const shadow = host.attachShadow({ mode: TEST_MODE ? "open" : "closed" });
const style = document.createElement("style");
style.textContent = buildTooltipCss();

const popup = document.createElement("div");
popup.className = "Popup";
popup.setAttribute("role", "tooltip");
popup.dataset.open = "0";
popup.dataset.mode = "hidden";
popup.dataset.placement = "top";
popup.dataset.theme = resolveTooltipTheme();

const content = document.createElement("div");
content.className = "Content";
content.textContent = "";

const arrow = document.createElementNS("http://www.w3.org/2000/svg", "svg");
arrow.setAttribute("class", "Arrow");
arrow.setAttribute("viewBox", "0 0 16 8");
arrow.setAttribute("width", String(CONFIG.arrowWidthPx));
arrow.setAttribute("height", String(CONFIG.arrowHeightPx));
arrow.setAttribute("aria-hidden", "true");

const path = document.createElementNS("http://www.w3.org/2000/svg", "path");
path.setAttribute("d", "M8 0L16 8H0L8 0Z");
path.setAttribute("class", "ArrowPath");
arrow.appendChild(path);

popup.appendChild(content);
popup.appendChild(arrow);
shadow.appendChild(style);
shadow.appendChild(popup);
(document.documentElement || document.body).appendChild(host);

ui = { host, shadow, popup, content, hoverBubble: null, hoverBubbleContent: null };

